import React from 'react';
import { FaComments, FaUserCircle } from 'react-icons/fa';
import logo from '../assets/logo.png'; // Asegúrate que esté bien

const Header = () => {
  return (
    <header className="w-full flex justify-between items-center px-10 py-4 bg-white">
      <FaComments size={28} className="text-black" />

      <img src={logo} alt="Logo Bicentenario" className="h-16 object-contain" />

      <FaUserCircle size={30} className="text-black" />
    </header>
  );
};

export default Header;
